import lxml.etree as ET

def process_soap_request(request):
    # Parse the SOAP envelope and extract the message body
    root = ET.fromstring(request)
    soap_env = root.find(".//{http://schemas.xmlsoap.org/soap/envelope/}Envelope")
    if soap_env is not None:
        # Validate the SOAP envelope against the DTD
        dtd = ET.DTD("file://path/to/dtd/file.dtd")
        if not dtd.validate(soap_env):
            raise ValueError("Invalid SOAP envelope")
        message_body = soap_env.find(".//{http://schemas.xmlsoap.org/soap/envelope/}Body")
        if message_body is not None:
            # Process the message body
            print(message_body.text)
    else:
        raise ValueError("Invalid SOAP envelope")